INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('bookkeeper-moex-01949', 'bookkeeper', 'bookkeeper-moex-103-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '黃崑巖：「有教養的人是有智慧的人，要達到這境界，光是有知識還不能稱得上有 教養。教養的重要要素是對自己存在的意義充分了解，而這種自覺出自於自身對周 遭環境的相對位置的正確概念。自身與環境，包括自身與別人或與社會的關係要弄 清楚。知道了這種關係脈絡，我們的進退才有分寸又能見好就收。」（《給青年學 生的十封信》）下列選項何者合乎文中所說教養的特質？', '["寬以待人，嚴以律己", "忠人之事，克盡己職", "知己知彼，行己有方", "捨己為公，有容乃大"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01950', 'bookkeeper', 'bookkeeper-moex-103-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '我們的社會結構原則，建立在一系列不等同的價值取向上面。這個價值系列的頂端 是天下、國家，底部躺著個人。這個「個人」，格物致知的修身工夫，意義不在探 討「本人」存在的意義，也不是為了追求對外在世界的認知，而是為了把自己準備 完善，以實現家族、國家和天下的和諧穩定。（劉大任〈賭〉）下列選項何者最接 近上文所述之文化？', '["個人主義", "群體主義", "存在主義", "人本主義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01951', 'bookkeeper', 'bookkeeper-moex-103-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '皮克斯動畫導演柏德曾說：「員工士氣往往對電影預算帶來最大衝擊，但卻從來不 會顯現在預算表上。如果員工士氣低落，那麼你花的每一塊錢，實際上只會得到兩 毛五的價值。如果員工士氣高，那麼你花的每一塊錢，可能創造出三塊錢的價值。 每家公司都應該更重視員工士氣。」關於這段話表達的主旨，最適當的詮釋是：', '["員工士氣是電影成敗的關鍵", "員工士氣高可提高經費運用的產值", "員工士氣的高低落差可達到十二倍", "預算表並不能精確估算完整的收支情形 60210"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01952', 'bookkeeper', 'bookkeeper-moex-103-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '「當你越是潛水射魚的高手時，你的漁獲就會越少，因你會選擇你要的魚而不是濫 射。當你越是了解老人們的固執時，你就越是敬畏大自然的一切神靈，你就有義務 為山林的樹木祈福。」（夏曼‧藍波安〈敬畏海的神靈〉）下列選項何者較接近前 文意旨？', '["技進乎道，藝通乎神", "敬天愛物，取之有節", "擇善固執，持志以終", "雅好山水，悠然自得"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01953', 'bookkeeper', 'bookkeeper-moex-103-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '有些物品褪流行了，必須丟掉，才有空間容納新產品；有些價值觀落伍了，必須拋 棄，才能合乎時潮；有些道德觀過於迂腐，必須刪除，方能與時俱進，跟上所謂時 代的腳步。 是這樣嗎？願意尊重每一樣物品或食品被製造、種植出來所費的時間與勞力，因此 物盡其用，絕不浪費，是否已被掃入阿嬤級思維而遭到恥笑？（改寫自簡媜〈活得 像一條流浪狗〉） 根據上文，作者的態度是：', '["品德為尚", "愛屋及烏", "與時推移", "恆常惜物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01954', 'bookkeeper', 'bookkeeper-moex-103-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '孟嘗君特雞鳴狗盜之雄耳，豈足以言得士？不然，擅齊之強，得一士焉，宜可以南面 而制秦，尚何取雞鳴狗盜之力哉？（王安石〈讀孟嘗君傳〉）王安石認為孟嘗君：', '["虛心求才", "掩耳盜鈴", "不得賢士", "可制秦國"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01955', 'bookkeeper', 'bookkeeper-moex-103-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '忽逢桃花林，夾岸數百步，中無雜樹，芳草鮮美，落英繽紛。漁人甚異之，復前行， 欲窮其林。林盡水源，便得一山。山有小口，髣髴若有光。便捨船，從口入。初極 狹，纔通人。復行數十步，豁然開朗。土地平曠，屋舍儼然，有良田、美池、桑竹 之屬。阡陌交通，雞犬相聞。其中往來種作，男女衣著，悉如外人。黃髮垂髫，並 怡然自樂。見漁人，乃大驚，問所從來，具答之。便要還家，設酒殺雞作食。村中 聞有此人，咸來問訊，自云先世避秦時亂，率妻子邑人來此絕境，不復出焉，遂與 外人間隔。問今是何世，乃不知有漢，無論魏晉！（陶淵明〈桃花源記〉） 根據上文，下列敘述何者正確？', '["「芳草鮮美，落英繽紛」指暮春三月，草長花落，果實豐收可期", "「黃髮垂髫，並怡然自樂」指當地男童、女童無不自在歡樂嬉遊", "「便要還家，設酒殺雞作食」指設宴為漁夫餞行，要求儘速離開", "「不知有漢，無論魏晉」指對於中國各朝代遞嬗沿革，並不了解"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01956', 'bookkeeper', 'bookkeeper-moex-103-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '袁宗道〈答友人〉：「學未至圓通，合己見則是，違己見則非。如以南方之舟，笑 北方之車；以鶴脛之長，憎鳧脛之短也。夫不責己之有見，而責人之異見，豈不悖 哉！」下列選項何者最切合本文旨意？', '["學至圓通易於責人", "強調眾謀之中必有異見", "人常以己之長而責人之短", "意志堅定者不為異說動搖 60210"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01957', 'bookkeeper', 'bookkeeper-moex-103-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '一秀才買柴，曰：「荷薪者過來。」賣柴者因「過來」二字明白，擔到面前。 問曰：「其價幾何？」因「價」字明白，說了價錢。秀才曰：「外實而內虛，烟 多而焰少，請損之。」賣柴者不知說甚，荷的去了。……有一官府下鄉，問父 老曰：「近來黎庶何如？」父老曰：「今年梨樹好，只是蟲喫了些。」根據上文， 選擇最符合意旨的選項：', '["志不同道不合，不相為謀", "秀才、官員恃才傲物，賣弄所學", "平民百姓學識不足，無法與人溝通", "秀才、官員咬文嚼字，不能有效傳達訊息"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01958', 'bookkeeper', 'bookkeeper-moex-103-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '蓋鹿耳門內浩瀚之勢，不異大海，其下實皆淺沙，若深水可行舟處，不過一綫，而 又左右盤曲，非素熟水道者，不敢輕入，所以稱險。（郁永河《裨海紀遊》）清朝 時期鹿耳門水道以「險」著稱的主要原因是：', '["水勢浩瀚磅礡，有如大海", "河道彎曲複雜，容易迷路", "水下淤積多沙，航道彎狹", "水域危險著稱，嚮導難尋 閱讀下文，回答第19~20題 我問老闆，為什麼不放走呢？ 他說，他也不忍心看小鳥這樣，想放走，又捨不得。 我好想伸手打開籠子，任鳥自飛，可是我沒有。 後來，我又下山幾次，小鳥依舊在籠子裏。我第一次那種激盪的心緒，越來越平穩了。 到最近一次去小店，返程時，走到半山，才猛然想到，剛才在鳥籠旁出出入入，不知經 過多少次，竟然不曾看牠一眼，眉頭瞬間黯了下來。 我不是悲小鳥，而是悲自己。（粟耘〈塵埃譜〉）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
